const CURSED_SURCHARGE_RATE = 0.5;
const ENCHANTMENT_SURCHARGE_RATE = 0.3;
const ENCHANTMENT_THRESHOLD = 5;

const applyCursedSurcharge = (basePremium: number, isCursed: boolean): number => {
  if (!isCursed) return basePremium;
  return Math.ceil(basePremium * (1 + CURSED_SURCHARGE_RATE));
};

const applyEnchantmentSurcharge = (basePremium: number, enchantment?: number): number => {
  if (!enchantment || enchantment < ENCHANTMENT_THRESHOLD) return basePremium;
  return undefined;
};

